import ast
import sys
import tempfile
from pathlib import Path

import pytest

AC_UID = "d7653985e85603ea"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
REGEN = REPO_ROOT / "hooks" / "doc_sync" / "regen_readme.py"
TREE = REPO_ROOT / "hooks" / "doc_sync" / "tree.py"

REQUIRED_MEMBERS = {"agent-scores.json", "agent-scores.json.lock"}


def _extract_set_members(source_file: Path, name: str) -> set:
    tree = ast.parse(source_file.read_text(encoding="utf-8"))
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            for tgt in node.targets:
                if isinstance(tgt, ast.Name) and tgt.id == name:
                    if isinstance(node.value, (ast.Set, ast.List, ast.Tuple)):
                        out = set()
                        for elt in node.value.elts:
                            if isinstance(elt, ast.Constant) and isinstance(elt.value, str):
                                out.add(elt.value)
                        return out
    raise AssertionError(f"name {name!r} not found as an assignment to a set/list literal in {source_file}")


def test_AC_09():
    """
    GIVEN: hooks/doc_sync/regen_readme.py and hooks/doc_sync/tree.py are AST-parsed; the doc-sync filter is exercised against a fixture that simulates the ACTUAL leak path (build_tree starting INSIDE .claude where `specs/` is NOT dot-prefixed and is NOT filtered by the existing `startswith('.')` predicate)
    WHEN:  (a) AST membership of SKIP_NAMES (regen_readme.py) and SKIP_FILES (tree.py) is checked for both 'agent-scores.json' AND 'agent-scores.json.lock'; (b) the doc-sync filtering code path is exercised by importing the package via PYTHONPATH=$PWD and calling `tree_mod.build_tree(root / '.claude')` against a fixture containing BOTH a `.claude/specs/spec-foo/cp-state.json` (positive leak path) AND a `.claude/ordinary/specs/keep.txt` (negative-control path)
    THEN:  both Python sets contain BOTH literal string members; the runtime fixture output MUST include control file `normal.txt` and the negative-control file `keep.txt` (proving the dev's fix is PATH-AWARE), and MUST NOT include the tree-rendered tokens `specs/`, `spec-foo/`, or `cp-state.json` from the leak-path subtree
    """
    # (a) AST membership check on both source files
    regen_members = _extract_set_members(REGEN, "SKIP_NAMES")
    tree_members = _extract_set_members(TREE, "SKIP_FILES")
    missing_regen = REQUIRED_MEMBERS - regen_members
    missing_tree = REQUIRED_MEMBERS - tree_members
    assert not missing_regen, f"regen_readme.SKIP_NAMES missing: {missing_regen}"
    assert not missing_tree, f"tree.SKIP_FILES missing: {missing_tree}"

    # (b) runtime fixture against actual build_tree
    if str(REPO_ROOT) not in sys.path:
        sys.path.insert(0, str(REPO_ROOT))
    from hooks.doc_sync import tree as tree_mod

    with tempfile.TemporaryDirectory() as td:
        root = Path(td)
        claude_dir = root / ".claude"
        # positive leak path
        leak = claude_dir / "specs" / "spec-foo"
        leak.mkdir(parents=True)
        (leak / "cp-state.json").write_text("{}")
        # negative control — legitimate non-.claude/specs path
        ordinary = claude_dir / "ordinary" / "specs"
        ordinary.mkdir(parents=True)
        (ordinary / "keep.txt").write_text("z")
        # control file
        (claude_dir / "normal.txt").write_text("y")
        lines = tree_mod.build_tree(claude_dir)
        out = "\n".join(lines)

    assert "normal.txt" in out, f"build_tree did not include control file normal.txt: {out!r}"
    assert "keep.txt" in out, (
        f"build_tree suppressed legitimate ordinary/specs/keep.txt — fix is too broad: {out!r}"
    )
    assert "ordinary/" in out, (
        f"build_tree suppressed legitimate ordinary/ — fix is too broad: {out!r}"
    )
    assert "spec-foo/" not in out, (
        f"build_tree did NOT suppress leak-path spec-foo/: {out!r}"
    )
    assert "cp-state.json" not in out, (
        f"build_tree did NOT suppress leak-path cp-state.json: {out!r}"
    )
    # No top-level specs/ child directly under .claude
    top_level_lines = [
        ln for ln in lines
        if not (ln.startswith(" ") or ln.startswith("│") or ln.startswith("    "))
    ]
    assert not any(ln.endswith(" specs/") for ln in top_level_lines), (
        f"top-level specs/ child of .claude NOT suppressed: top_level={top_level_lines!r}"
    )
